# ============================================================
# Utility: Audit Logging
# ============================================================

def audit_log(event: str, details: dict):
    """Append an audit log entry."""
    entry = {
        "timestamp": time.time(),
        "event": event,
        "details": details,
    }
    with open(AUDIT_LOG_FILE, "a") as f:
        f.write(json.dumps(entry) + "\n")


# ============================================================
# Utility: API Token Management
# ============================================================

def load_api_tokens() -> dict:
    if os.path.exists(API_TOKENS_FILE):
        with open(API_TOKENS_FILE, "r") as f:
            return json.load(f)
    return {}


def save_api_tokens(tokens: dict):
    with open(API_TOKENS_FILE, "w") as f:
        json.dump(tokens, f, indent=2)


def hash_token(token: str) -> str:
    return hashlib.sha256(token.encode()).hexdigest()


def verify_token(credentials: HTTPAuthorizationCredentials = Depends(security)) -> str:
    """Verify the bearer token and return the associated user."""
    token = credentials.credentials
    token_hash = hash_token(token)
    tokens = load_api_tokens()
    if token_hash not in tokens:
        audit_log("auth_failure", {"token_prefix": token[:8] + "..."})
        raise HTTPException(status_code=401, detail="Invalid authentication token")
    return tokens[token_hash]["user"]


# ============================================================
# Utility: Rate Limiting
# ============================================================

def check_rate_limit(user: str):
    """Enforce rate limiting per user to prevent model inversion attacks."""
    now = time.time()
    if user not in rate_limit_store:
        rate_limit_store[user] = []

    # Clean old entries
    rate_limit_store[user] = [
        t for t in rate_limit_store[user] if now - t < RATE_LIMIT_WINDOW
    ]

    if len(rate_limit_store[user]) >= RATE_LIMIT_MAX_REQUESTS:
        audit_log("rate_limit_exceeded", {"user": user})
        raise HTTPException(
            status_code=429,
            detail=f"Rate limit exceeded. Max {RATE_LIMIT_MAX_REQUESTS} requests per {RATE_LIMIT_WINDOW}s.",
        )

    rate_limit_store[user].append(now)


# ============================================================
# Anti-Model-Inversion: Confidence Score Protection
# ============================================================

def apply_temperature_scaling(logits: np.ndarray, temperature: float) -> np.ndarray:
    """Apply temperature scaling to soften probability distributions,
    making it harder to extract precise model information."""
    scaled = logits / temperature
    exp_scaled = np.exp(scaled - np.max(scaled))
    return exp_scaled / exp_scaled.sum()


def add_differential_privacy_noise(
    probabilities: np.ndarray, scale: float
) -> np.ndarray:
    """Add calibrated Laplacian noise to probability scores to prevent
    precise gradient estimation for model inversion."""
    noise = np.random.laplace(0, scale, size=probabilities.shape)
    noisy_probs = probabilities + noise
    # Clip and renormalize
    noisy_probs = np.clip(noisy_probs, 0, None)
    total = noisy_probs.sum()
    if total > 0:
        noisy_probs /= total
    else:
        noisy_probs = np.ones_like(noisy_probs) / len(noisy_probs)
    return noisy_probs


def sanitize_confidence_scores(
    class_names: list[str], probabilities: np.ndarray
) -> dict:
    """Apply all anti-model-inversion protections to confidence scores."""
    # 1. Apply temperature scaling to soften the distribution
    softened = apply_temperature_scaling(np.log(probabilities + 1e-10), TEMPERATURE)

    # 2. Add differential privacy noise
    noisy = add_differential_privacy_noise(softened, NOISE_SCALE)

    # 3. Round to limited precision
    rounded = np.round(noisy, CONFIDENCE_PRECISION)

    # 4. Build results, suppressing very low scores
    results = {}
    for name, score in zip(class_names, rounded):
        if score >= MIN_CONFIDENCE_THRESHOLD:
            results[name] = float(score)

    # 5. Sort by confidence and limit to top-K
    sorted_results = dict(
        sorted(results.items(), key=lambda x: x[1], reverse=True)[:TOP_K_RESULTS]
    )

    # 6. Renormalize the visible scores so they sum to ~1.0
    total = sum(sorted_results.values())
    if total > 0:
        sorted_results = {
            k: round(v / total, CONFIDENCE_PRECISION)
            for k, v in sorted_results.items()
        }

    return sorted_results


# ============================================================
# Model Training
