class FaceRecognitionModel:
    def __init__(self):
        self.classifier: Optional[CalibratedClassifierCV] = None
        self.label_encoder: Optional[LabelEncoder] = None
        self.is_trained = False

    def train(self, data_dir: str) -> dict:
        """Train the face recognition model on employee photos."""
        data_path = Path(data_dir)
        if not data_path.exists():
            raise FileNotFoundError(f"Training data directory not found: {data_dir}")

        encodings_list = []
        labels_list = []

        employee_dirs = [d for d in data_path.iterdir() if d.is_dir()]
        if not employee_dirs:
            raise ValueError("No employee directories found in training data directory")

        training_stats = {}

        for employee_dir in employee_dirs:
            employee_name = employee_dir.name
            image_files = list(employee_dir.glob("*.jpg")) + \
                          list(employee_dir.glob("*.jpeg")) + \
                          list(employee_dir.glob("*.png"))

            count = 0
            for img_path in image_files:
                image = face_recognition.load_image_file(str(img_path))
                face_encs = face_recognition.face_encodings(image)

                if len(face_encs) == 1:
                    encodings_list.append(face_encs[0])
                    labels_list.append(employee_name)
                    count += 1
                elif len(face_encs) > 1:
                    # Skip images with multiple faces for training purity
                    pass

            training_stats[employee_name] = count

        if len(encodings_list) < 2:
            raise ValueError("Insufficient training data. Need at least 2 face encodings.")

        unique_labels = set(labels_list)
        if len(unique_labels) < 2:
            raise ValueError("Need at least 2 different employees for classification.")

        X = np.array(encodings_list)
        self.label_encoder = LabelEncoder()
        y = self.label_encoder.fit_transform(labels_list)

        # Use SVC with probability calibration
        base_clf = SVC(kernel="rbf", gamma="scale", C=10.0)
        self.classifier = CalibratedClassifierCV(base_clf, cv=min(3, min(
            np.bincount(y)
        )))
        self.classifier.fit(X, y)

        # Save model (without raw training data)
        with open(MODEL_PATH, "wb") as f:
            pickle.dump(self.classifier, f)
        with open(ENCODER_PATH, "wb") as f:
            pickle.dump(self.label_encoder, f)

        self.is_trained = True

        audit_log("model_trained", {
            "num_employees": len(unique_labels),
            "total_samples": len(encodings_list),
            "stats": training_stats,
        })

        return {
            "status": "trained",
            "num_employees": len(unique_labels),
            "employees": training_stats,
            "total_samples": len(encodings_list),
        }

    def load(self) -> bool:
        """Load a previously trained model."""
        if os.path.exists(MODEL_PATH) and os.path.exists(ENCODER_PATH):
            with open(MODEL_PATH, "rb") as f:
                self.classifier = pickle.load(f)
            with open(ENCODER_PATH, "rb") as f:
                self.label_encoder = pickle.load(f)
            self.is_trained = True
            return True
        return False

    def predict(self, face_encoding: np.ndarray) -> dict:
        """Predict with anti-model-inversion protections."""
        if not self.is_trained:
            raise RuntimeError("Model is not trained")

        encoding_2d = face_encoding.reshape(1, -1)
        raw_probabilities = self.classifier.predict_proba(encoding_2d)[0]
        class_names = list(self.label_encoder.classes_)

        # Apply anti-model-inversion sanitization
        sanitized_scores = sanitize_confidence_scores(class_names, raw_probabilities)

        # Determine best match
        best_match = max(sanitized_scores, key=sanitized_scores.get) if sanitized_scores else "unknown"
        best_confidence = sanitized_scores.get(best_match, 0.0)

        return {
            "best_match": best_match,
            "best_confidence": best_confidence,
            "confidence_distribution": sanitized_scores,
            "num_faces_in_model": len(class_names),
            "results_shown": len(sanitized_scores),
            "note": "Scores are sanitized with differential privacy protections",
        }


# Global model instance
