# API Endpoints
# ============================================================

ADMIN_SECRET = os.environ.get("ADMIN_SECRET", "change-this-secret-in-production")


@app.post("/admin/create-token", response_model=TokenCreateResponse)
async def create_api_token(request: TokenCreateRequest):
    """Create a new API token (admin only)."""
    if request.admin_secret != ADMIN_SECRET:
        raise HTTPException(status_code=403, detail="Invalid admin secret")

    token = secrets.token_urlsafe(32)
    token_hash_val = hash_token(token)

    tokens = load_api_tokens()
    tokens[token_hash_val] = {
        "user": request.user,
        "created_at": time.time(),
    }
    save_api_tokens(tokens)

    audit_log("token_created", {"user": request.user})

    return TokenCreateResponse(
        token=token,
        user=request.user,
        message="Store this token securely. It cannot be retrieved again.",
    )


