@app.post("/recognize", response_model=RecognitionResponse)
async def recognize_face(
    file: UploadFile = File(...),
    user: str = Depends(verify_token),
):
    """Recognize faces in an uploaded image.

    Returns confidence scores with anti-model-inversion protections:
    - Temperature-scaled probability distributions
    - Differential privacy noise injection
    - Precision rounding
    - Top-K result limiting
    - Low-confidence suppression
    """
    # Rate limiting
    check_rate_limit(user)

    if not model.is_trained:
        raise HTTPException(
            status_code=503,
            detail="Model not trained. Please call /train first.",
        )

    # Validate file type
    if file.content_type not in ["image/jpeg", "image/png", "image/jpg"]:
        raise HTTPException(
            status_code=400,
            detail="Invalid file type. Please upload a JPEG or PNG image.",
        )

    # Read and validate image
    contents = await file.read()

    # Limit file size (10MB)
    if len(contents) > 10 * 1024 * 1024:
        raise HTTPException(status_code=400, detail="File too large. Max 10MB.")

    try:
        pil_image = Image.open(io.BytesIO(contents))
        # Convert to RGB if necessary
        if pil_image.mode != "RGB":
            pil_image = pil_image.convert("RGB")
        image_array = np.array(pil_image)
    except Exception:
        raise HTTPException(status_code=400, detail="Could not process image file.")

    # Detect faces
    face_locations = face_recognition.face_locations(image_array)
    face_encodings = face_recognition.face_encodings(image_array, face_locations)

    if not face_encodings:
        audit_log("recognition_no_face", {"user": user, "filename": file.filename})
        return RecognitionResponse(faces_detected=0, results=[])

    results = []
    for encoding in face_encodings:
        prediction = model.predict(encoding)
        results.append(RecognitionResult(**prediction))

    audit_log("recognition_success", {
        "user": user,
        "filename": file.filename,
        "faces_detected": len(face_encodings),
        "top_matches": [r.best_match for r in results],
    })

    return RecognitionResponse(
        faces_detected=len(face_encodings),
        results=results,
    )


